    out: dict[str, Decimal] = {"subtotal": Decimal("0"), "tax_amount": Decimal("0"), "total_amount": Decimal("0")}
    for line in text.splitlines():
        low = line.lower()
        m = CURRENCY_RE.search(line)
        if not m:
            continue
        amt = _to_decimal(m.group(1))
        if "subtotal" in low and out["subtotal"] == 0:
            out["subtotal"] = amt

